object Routes { const val ONBOARDING = "onboarding"; const val HOME = "home"; const val TRACKING = "tracking" }

@Composable fun AppNavigation():
  val context = LocalContext.current
  val db = (context.applicationContext as MofitApplication).database
  val profile by db.workoutDao().getProfile().collectAsState(initial=null)
  var profileLoaded by remember { mutableStateOf(false) }

  LaunchedEffect(profile) { if (!profileLoaded) profileLoaded = true }

  if (!profileLoaded) {
    Box(Modifier.fillMaxSize().background(Color.Black)) // splash
    return
  }

  val navController = rememberNavController()
  val startDest = if (profile != null) "main" else Routes.ONBOARDING

  NavHost(navController, startDestination=startDest):
    composable(Routes.ONBOARDING): OnboardingScreen(onComplete={ navController.navigate("main") { popUpTo(Routes.ONBOARDING) { inclusive=true } } })
    composable("main"): MainTabScreen(onStartWorkout={ navController.navigate(Routes.TRACKING) })
    composable(Routes.TRACKING): TrackingScreen(onClose={ navController.popBackStack() })

@Composable fun MainTabScreen(onStartWorkout: () -> Unit):
  val tabIndex = remember { mutableStateOf(0) }
  Scaffold(
    bottomBar = {
      NavigationBar(containerColor=Color.Black, contentColor=Color(0xFF33CC66)):
        NavigationBarItem(selected=tabIndex.value==0, onClick={tabIndex.value=0}, icon={Icon(Icons.Default.Home,'홈')}, label={Text('홈')}, colors=...)
        NavigationBarItem(selected=tabIndex.value==1, onClick={tabIndex.value=1}, icon={Icon(Icons.Default.DateRange,'기록')}, label={Text('기록')})
        NavigationBarItem(selected=tabIndex.value==2, onClick={tabIndex.value=2}, icon={Icon(Icons.Default.Star,'코칭')}, label={Text('코칭')})
    }
  ) { padding ->
    Box(Modifier.padding(padding)):
      when(tabIndex.value):
        0 -> HomeScreen(onStartWorkout=onStartWorkout)
        1 -> HistoryScreen()
        2 -> CoachingScreen()
  }
  NavigationBar uses selectedContentColor=Color(0xFF33CC66), unselectedContentColor=Color(0xFF666666), indicatorColor=Color(0xFF1A1A1A).

